const sqlite3 = require('sqlite3').verbose();
const path = '/Users/philliplowe/.openclaw/workspaces/sol/utopia-deli-revamp/orders.db';
const merged = $("MP Merge").first().json;
const customer = merged.customer || {};
const items = merged.items || [];
const pricing = merged.pricing || {};
const paymentLink = merged.payment_link || {};
const linkUrl = paymentLink.url || paymentLink.long_url || '';

return new Promise((resolve) => {
  const db = new sqlite3.Database(path, (err) => {
    if (err) { resolve([{ json: { db_error: err.message } }]); return; }
    db.run(
      'INSERT INTO orders (order_id, customer_name, customer_email, customer_phone, customer_city, customer_county, cart_json, subtotal_cents, tax_cents, total_cents, square_payment_link, square_order_id, notes, status, source) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)',
      [
        merged.order_id || '',
        customer.name || '',
        customer.email || '',
        customer.phone || '',
        customer.city || 'Little Rock',
        customer.county || '',
        JSON.stringify(items),
        pricing.subtotal || 0,
        pricing.tax || 0,
        pricing.total || 0,
        linkUrl,
        merged.square_order_id || merged.order_id || '',
        customer.notes || merged.notes || '',
        'pending',
        'meal-prep'
      ],
      function(err) {
        if (err) resolve([{ json: { db_error: err.message } }]);
        else resolve([{ json: { db_saved: true, db_rowid: this.lastID } }]);
        db.close();
      }
    );
  });
});

const merged = $("MP Merge").first().json;
const dbResult = $("Save to SQLite2").first().json;

const paymentLink = merged.payment_link || {};
const squareLink = (paymentLink.url || paymentLink.long_url) || merged.payment_link || '';

return {
 json: {
 ok: true,
 message: 'Order received! Check your email for payment link.',
 square_link: squareLink,
 order_id: merged.order_id || '',
 total_cents: merged.pricing?.total || 0,
 db_saved: dbResult.db_saved || false
 }
};
